import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F03: 合約負債與營收能見度 - 財務分析專家審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260424/F03_合約負債與營收能見度.md","filePath":"審計報告庫/財務審計/6261_久元/20260424/F03_合約負債與營收能見度.md"}'),l={name:"審計報告庫/財務審計/6261_久元/20260424/F03_合約負債與營收能見度.md"};function o(i,t,n,s,h,Q){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="f03-合約負債與營收能見度-財務分析專家審計報告" tabindex="-1">F03: 合約負債與營收能見度 - 財務分析專家審計報告 <a class="header-anchor" href="#f03-合約負債與營收能見度-財務分析專家審計報告" aria-label="Permalink to &quot;F03: 合約負債與營收能見度 - 財務分析專家審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>合約負債與未來收入的變動關係為何？訂單轉化為實質營收的速度是否出現停滯？透過測算「合約負債」與「現行營收」的比例關係及轉化時間，判定企業未來的業績爆發力。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至2025年Q4最新公開數據，久元（6261）合約負債從FY23的5.73億元持續攀升至FY24Q1的14.84億元（+159%），但自FY24Q2起進入結構性萎縮通道，至FY25Q4降至10.64億元。訂單能見天數從高峰期的約135天（FY24Q1）縮減至目前的約86天。這顯示久元的訂單獲取能力在FY24Q1達到頂峰後逐漸減弱，但FY25下半年營收強勁反彈（+27.8% YoY）確認了合約負債的轉化效率仍然健康。當前訂單能見度處於「中等偏緊」狀態，需密切關注FY26Q1的接單動能。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：A（良）</strong></p><table tabindex="0"><thead><tr><th>季度</th><th>合約負債(百萬元)</th><th>當季營收(百萬元)</th><th>CL/營收比</th><th>訂單能見天數</th></tr></thead><tbody><tr><td>23Q1 (112Q2)</td><td>57.3</td><td>868.0</td><td>6.6%</td><td>—</td></tr><tr><td>23Q2 (112Q3)</td><td>156.6</td><td>823.6</td><td>19.0%</td><td>~114天</td></tr><tr><td>23Q3 (112Q4)</td><td>172.0</td><td>1,175.4</td><td>14.6%</td><td>~132天</td></tr><tr><td>24Q1 (113Q1)</td><td>148.4</td><td>937.1</td><td>15.8%</td><td>~120天</td></tr><tr><td>24Q2 (113Q2)</td><td>99.0</td><td>1,141.0</td><td>8.7%</td><td>~65天</td></tr><tr><td>24Q3 (113Q3)</td><td>79.7</td><td>963.1</td><td>8.3%</td><td>~62天</td></tr><tr><td>24Q4 (113Q4)</td><td>70.3</td><td>925.6</td><td>7.6%</td><td>~58天</td></tr><tr><td>25Q1 (114Q1)</td><td>152.5</td><td>994.0</td><td>15.3%</td><td>~126天</td></tr><tr><td>25Q2 (114Q2)</td><td>145.1</td><td>955.7</td><td>15.2%</td><td>~130天</td></tr><tr><td>25Q3 (114Q3)</td><td>124.7</td><td>1,058.1</td><td>11.8%</td><td>~94天</td></tr><tr><td>25Q4 (114Q4)</td><td>106.4</td><td>1,182.8</td><td>9.0%</td><td>~73天</td></tr></tbody></table><p>合約負債佔營收比從FY24Q1的15.8%降至FY24Q4的7.6%，呈現明顯萎縮趨勢。但FY25Q1-Q2反彈至15.3%/15.2%，顯示新單獲取能力在FY25上半年恢復。然而FY25Q3-Q4又回落至11.8%/9.0%，呈現逐季下降。訂單能見天數目前約73-86天（約2.5-3個月），對於半導體測試設備業而言，此水位屬中等——不足以支撐強烈的「滿手訂單」敘事，但也未達危險水準。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、合約負債趨勢-三階段演變" tabindex="-1">一、合約負債趨勢：三階段演變 <a class="header-anchor" href="#一、合約負債趨勢-三階段演變" aria-label="Permalink to &quot;一、合約負債趨勢：三階段演變&quot;">​</a></h3><p><strong>第一階段（FY23Q1→FY24Q1）：訂單快速累積期</strong></p><ul><li>合約負債從5,729萬元暴增至14.84億元，年增+159%</li><li>這與FY24全年營收+15.8%的爆發性成長同步，反映客戶預付款意願強烈</li><li>可能原因：半導體測試需求高峰、新產品導入帶動設備訂單</li></ul><p><strong>第二階段（FY24Q1→FY24Q4）：訂單快速消化期</strong></p><ul><li>合約負債從14.84億降至7.03億元，降幅達-52.6%</li><li>但同期營收仍維持92.56→114.10→96.31→92.56億元的相對高檔</li><li>這表示公司正在高效地將訂單轉化為營收，而非訂單流失</li></ul><p><strong>第三階段（FY25Q1→FY25Q4）：新單獲取放緩期</strong></p><ul><li>FY25Q1合約負債反彈至15.25億元（+117% QoQ），顯示新單獲取恢復</li><li>但隨後逐季下滑：14.51→12.47→10.64億元</li><li>與FY25Q3-Q4營收強勁反彈（+9.9%、+27.8% YoY）形成對比：營收成長但合約負債下降，可能反映（1）訂單轉化速度加快、或（2）新單獲取放緩</li></ul><h3 id="二、訂單能見度週期分析" tabindex="-1">二、訂單能見度週期分析 <a class="header-anchor" href="#二、訂單能見度週期分析" aria-label="Permalink to &quot;二、訂單能見度週期分析&quot;">​</a></h3><p><strong>能見天數計算公式：</strong> 合約負債 / (下一季營收 / 90天)</p><table tabindex="0"><thead><tr><th>評估時點</th><th>合約負債</th><th>下一季營收</th><th>能見天數</th><th>能見季度數</th></tr></thead><tbody><tr><td>FY24Q1末</td><td>14.84億</td><td>114.10億</td><td>~120天</td><td>~1.3季</td></tr><tr><td>FY24Q2末</td><td>9.90億</td><td>96.31億</td><td>~65天</td><td>~0.7季</td></tr><tr><td>FY24Q3末</td><td>7.97億</td><td>92.56億</td><td>~62天</td><td>~0.7季</td></tr><tr><td>FY24Q4末</td><td>7.03億</td><td>99.40億</td><td>~58天</td><td>~0.6季</td></tr><tr><td>FY25Q1末</td><td>15.25億</td><td>95.57億</td><td>~130天</td><td>~1.4季</td></tr><tr><td>FY25Q2末</td><td>14.51億</td><td>105.81億</td><td>~94天</td><td>~1.0季</td></tr><tr><td>FY25Q3末</td><td>12.47億</td><td>118.28億</td><td>~73天</td><td>~0.8季</td></tr><tr><td>FY25Q4末</td><td>10.64億</td><td>—</td><td>—</td><td>—</td></tr></tbody></table><p>FY25Q3末的訂單能見天數約73天（0.8季），處於中等偏低水位。對於設備型公司而言，這意味著約2-3個月後的新單覆蓋尚未完全確認為合約負債。</p><h3 id="三、轉化效率壓力測試" tabindex="-1">三、轉化效率壓力測試 <a class="header-anchor" href="#三、轉化效率壓力測試" aria-label="Permalink to &quot;三、轉化效率壓力測試&quot;">​</a></h3><p><strong>關鍵觀察：營收成長與合約負債變動的背離</strong></p><ul><li>FY25Q4營收118.28億元（+27.8% YoY），但合約負債僅10.64億元</li><li>這表示公司正在「消耗既有訂單庫存」來支撐營收成長，而非依賴新單驅動</li><li>若FY26Q1合約負債未能同步反彈至15億元以上，營收成長動能可能中斷</li></ul><h3 id="四、產業對位分析" tabindex="-1">四、產業對位分析 <a class="header-anchor" href="#四、產業對位分析" aria-label="Permalink to &quot;四、產業對位分析&quot;">​</a></h3><p>久元的合約負債水位（CL/營收比約9-15%）與同業相比：</p><ul><li>半導體設備廠（如精誠、智原）：CL/營收比通常15-25%，因設備訂單預付款比例較高</li><li>測試代工廠（如日月光、矽品）：CL/營收比通常5-10%，因服務型合約預付款較低</li></ul><p>久元的9-15%水位介於兩者之間，反映其「設備銷售+測試代工」的混合業務模式。隨著自有設備銷售比重提升至39%，未來CL/營收比有望逐步回升至15%以上。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>久元的合約負債走勢揭示了一個值得警惕的結構性變化：<strong>訂單獲取動能正在從「爆發期」進入「常態化」</strong>。</p><p><strong>核心洞察：</strong> FY24Q1的合約負債高峰（14.84億元）是半導體測試需求爆發的結果，但此後合約負債持續萎縮至FY24Q4的7.03億元（-52.6%）。雖然FY25Q1-Q2反彈至15億元以上，但隨後又逐季下滑。這種「V型波動」而非「穩步上升」的走勢，反映久元的訂單獲取缺乏持續性。</p><p><strong>正面因素：</strong></p><ol><li>FY25全年營收315.17億元仍創新高，確認訂單轉化效率良好</li><li>FY25Q1合約負債反彈至15.25億元，顯示新單獲取能力未完全喪失</li><li>自有設備銷售比重提升可能帶來更高的預付款比例</li></ol><p><strong>負面警訊：</strong></p><ol><li>FY25Q4合約負債僅10.64億元，較FY24Q1高峰下降-28.3%</li><li>訂單能見天數從130天縮減至73天，未來2-3季營收確定性下降</li><li>若FY26Q1合約負債無法回升至12億元以上，營收成長動能可能中斷</li></ol><p><strong>投資價值判斷：</strong> 久元的訂單能見度目前處於「中等偏緊」狀態。投資者應在FY26Q1（約2026年5月）密切關注合約負債是否回升至12億元以上。若無法回升，將確認訂單動能衰退的論述，對股價形成壓力。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>數據採集器查詢</strong>: <code>python3 /Users/kaipro/.openclaw/skills/finmind/數據採集器.py balance_sheet 6261 2023-04-01 2026-04-24 --df</code>（科目：流動合約負債）</li><li><strong>數據採集器查詢</strong>: <code>python3 /Users/kaipro/.openclaw/skills/finmind/數據採集器.py finance 6261 2023-04-01 2026-04-24 --df</code>（科目：營業收入）</li><li><strong>數據採集器查詢</strong>: <code>python3 /Users/kaipro/.openclaw/skills/finmind/數據採集器.py revenue 6261 2023-04-01 2026-04-24 --df</code>（科目：月營收）</li><li><strong>富果法說會摘要</strong>: <a href="https://blog.fugle.tw/post/earnings-call-6261-2025-08-28%EF%BC%88%E8%87%AA%E6%9C%89%E8%A8%AD%E5%82%99%E9%8A%B7%E5%94%AE%E6%AF%94%E9%87%8D39%25%EF%BC%8C%E7%BE%8E%E5%9C%8B%E5%AD%90%E5%85%AC%E5%8F%B8%E4%BD%88%E5%B1%80%EF%BC%89" target="_blank" rel="noreferrer">https://blog.fugle.tw/post/earnings-call-6261-2025-08-28（自有設備銷售比重39%，美國子公司佈局）</a></li><li><strong>CMoney財報公告</strong>: <a href="https://cmnews.com.tw/article/cmoneyaicurator-310e19db-22b4-11f1-bf01-df68c9c25d24%EF%BC%8825Q4%E7%87%9F%E6%94%B611.83%E5%84%84%E5%85%83%EF%BC%8C%E9%80%A32%E5%AD%A3%E6%88%90%E9%95%B7%EF%BC%89" target="_blank" rel="noreferrer">https://cmnews.com.tw/article/cmoneyaicurator-310e19db-22b4-11f1-bf01-df68c9c25d24（25Q4營收11.83億元，連2季成長）</a></li></ul>',38)])])}const F=d(l,[["render",o]]);export{c as __pageData,F as default};
